define i8 @shl_add(i8 %x, i8 %y) {
  %sh0 = shl i8 %x, 3
  %r = add i8 %sh0, %y
  %sh1 = shl i8 %r, 2
  ret i8 %sh1
}

define <2 x i8> @shl_add_nonuniform(<2 x i8> %x, <2 x i8> %y) {
  %sh0 = shl <2 x i8> %x, <i8 3, i8 4>
  %r = add <2 x i8> %sh0, %y
  %sh1 = shl <2 x i8> %r, <i8 2, i8 0>
  ret <2 x i8> %sh1
}
